**Protocol Specification**

**Magic**: `4D 56` ("MV")  
**Version**: `01` (uint8, always 1)  
**Type**: `01` = Login, `02` = Message (uint8)  
**Length**: `uint16` (big-endian) — length of the *payload* that follows (excluding header)

### Payload formats

**Type 1 — Login**
```
uint16     username_length
byte[]     username (ASCII, no null terminator)
uint16     password_length
byte[]     password (ASCII, no null terminator)
```

**Type 2 — Message**
```
uint16     message_length
byte[]     message (ASCII)
uint32     room_id (big-endian)
```

Total header size = 5 bytes (`MV` + version + type + length).

---

**Python Parser / Serializer**

```python
from dataclasses import dataclass
from typing import Union
import struct


class PacketType:
    LOGIN = 1
    MESSAGE = 2


@dataclass
class LoginPacket:
    username: str
    password: str
    packet_type: int = PacketType.LOGIN


@dataclass
class MessagePacket:
    message: str
    room_id: int
    packet_type: int = PacketType.MESSAGE


Packet = Union[LoginPacket, MessagePacket]


class MVProtocol:
    MAGIC = b'MV'
    VERSION = 1
    HEADER_FMT = '>BBH'          # Magic is checked manually, then version + type + length
    HEADER_SIZE = 5

    @staticmethod
    def parse(data: bytes) -> Packet:
        if len(data) < MVProtocol.HEADER_SIZE:
            raise ValueError("Data too short for header")

        magic = data[0:2]
        if magic != MVProtocol.MAGIC:
            raise ValueError(f"Bad magic: {magic.hex()}")

        version, pkt_type, length = struct.unpack(
            MVProtocol.HEADER_FMT, data[2:5]
        )

        if version != MVProtocol.VERSION:
            raise ValueError(f"Unsupported version: {version}")

        if len(data) - MVProtocol.HEADER_SIZE < length:
            raise ValueError("Packet truncated")

        payload = data[MVProtocol.HEADER_SIZE:MVProtocol.HEADER_SIZE + length]

        if pkt_type == PacketType.LOGIN:
            return MVProtocol._parse_login(payload)
        elif pkt_type == PacketType.MESSAGE:
            return MVProtocol._parse_message(payload)
        else:
            raise ValueError(f"Unknown packet type: {pkt_type}")

    @staticmethod
    def _parse_login(payload: bytes) -> LoginPacket:
        if len(payload) < 4:
            raise ValueError("Login payload too small")

        user_len = struct.unpack('>H', payload[0:2])[0]
        offset = 2

        if len(payload) < offset + user_len + 2:
            raise ValueError("Login payload truncated")

        username = payload[offset:offset + user_len].decode('ascii')
        offset += user_len

        pass_len = struct.unpack('>H', payload[offset:offset + 2])[0]
        offset += 2

        if len(payload) < offset + pass_len:
            raise ValueError("Password truncated")

        password = payload[offset:offset + pass_len].decode('ascii')

        return LoginPacket(username=username, password=password)

    @staticmethod
    def _parse_message(payload: bytes) -> MessagePacket:
        if len(payload) < 6:  # 2 + msg + 4
            raise ValueError("Message payload too small")

        msg_len = struct.unpack('>H', payload[0:2])[0]
        if len(payload) < 2 + msg_len + 4:
            raise ValueError("Message payload truncated")

        message = payload[2:2 + msg_len].decode('ascii')
        room_id = struct.unpack('>I', payload[2 + msg_len:])[0]

        return MessagePacket(message=message, room_id=room_id)

    @staticmethod
    def serialize(packet: Packet) -> bytes:
        if isinstance(packet, LoginPacket):
            return MVProtocol._serialize_login(packet)
        elif isinstance(packet, MessagePacket):
            return MVProtocol._serialize_message(packet)
        else:
            raise TypeError("Unknown packet type")

    @staticmethod
    def _serialize_login(pkt: LoginPacket) -> bytes:
        user_bytes = pkt.username.encode('ascii')
        pass_bytes = pkt.password.encode('ascii')

        payload = (
            struct.pack('>H', len(user_bytes)) +
            user_bytes +
            struct.pack('>H', len(pass_bytes)) +
            pass_bytes
        )

        return MVProtocol._wrap(PacketType.LOGIN, payload)

    @staticmethod
    def _serialize_message(pkt: MessagePacket) -> bytes:
        msg_bytes = pkt.message.encode('ascii')
        payload = (
            struct.pack('>H', len(msg_bytes)) +
            msg_bytes +
            struct.pack('>I', pkt.room_id)
        )
        return MVProtocol._wrap(PacketType.MESSAGE, payload)

    @staticmethod
    def _wrap(packet_type: int, payload: bytes) -> bytes:
        length = len(payload)
        header = struct.pack(
            '>BBH', MVProtocol.VERSION, packet_type, length
        )
        return MVProtocol.MAGIC + header + payload


# Example usage / test
if __name__ == "__main__":
    p1 = bytes.fromhex("4d 56 01 00 0c 68 65 6c 6c 6f 5f 77 6f 72 6c 64 00 00 00 05 61 64 6d 69 6e")
    parsed = MVProtocol.parse(p1)
    print(parsed)

    serialized = MVProtocol.serialize(parsed)
    print("Round-trip matches:", serialized == p1)
```

This parser correctly handles both provided login packets and the message packet, and can serialize them back to the exact same wire format.
